"""Test the new JSON extraction + validation logic in standup-composer.sh v7."""
import json, re, sys

def extract_json_object(t):
    t = t.strip()
    if t.startswith('```'):
        lines = t.split('\n')
        end = len(lines)
        for i in range(len(lines) - 1, 0, -1):
            if lines[i].strip().startswith('```'):
                end = i
                break
        t = '\n'.join(lines[1:end])
    start = t.find('{')
    if start == -1:
        return None
    depth = 0
    in_str = False
    esc = False
    end = -1
    for i in range(start, len(t)):
        c = t[i]
        if in_str:
            if esc:
                esc = False
            elif c == '\\':
                esc = True
            elif c == '"':
                in_str = False
            continue
        if c == '"':
            in_str = True
        elif c == '{':
            depth += 1
        elif c == '}':
            depth -= 1
            if depth == 0:
                end = i
                break
    if end == -1:
        return None
    return t[start:end + 1]

def validate(text):
    obj_text = extract_json_object(text)
    if obj_text is None:
        return None, "no balanced object"
    try:
        d = json.loads(obj_text)
    except Exception as e:
        return None, f"parse error: {e}"

    bs = d.get('businessStream')
    fm = d.get('frameworkMaturity')
    if not isinstance(bs, str) or len(bs.strip()) < 5:
        return None, f"businessStream invalid"
    if not isinstance(fm, str) or len(fm.strip()) < 5:
        return None, f"frameworkMaturity invalid"

    progress = d.get('progress')
    if isinstance(progress, list):
        items = [str(x).strip() for x in progress if str(x).strip()]
        if not items:
            return None, "progress list empty"
        d['progress'] = '\n'.join(item if item.startswith('•') else f'• {item}' for item in items)
    elif isinstance(progress, str):
        if len(progress.strip()) < 10:
            return None, "progress too short"
    else:
        return None, f"progress wrong type: {type(progress).__name__}"

    rtb = d.get('rtb')
    if not isinstance(rtb, dict):
        return None, "rtb not dict"
    for key in ('rose', 'thorn', 'bud'):
        val = rtb.get(key)
        if not isinstance(val, str) or len(val.strip()) < 3:
            return None, f"rtb.{key} invalid"
    return d, "OK"

# Test cases
test_cases = [
    ("clean JSON", '{"businessStream":"Aria did X. Y is in progress. Z blocked.","frameworkMaturity":"Shield CLEAR. Lex CLEAR.","progress":"• CHG-1 did A\\n• CHG-2 did B","rtb":{"rose":"good","thorn":"bad","bud":"next"}}'),
    ("markdown fence", '```json\n{"businessStream":"Aria did X. Y is in progress.","frameworkMaturity":"Shield CLEAR.","progress":["CHG-1 did A","CHG-2 did B"],"rtb":{"rose":"good","thorn":"bad","bud":"next"}}\n```'),
    ("with prose prefix", 'Here is the response:\n{"businessStream":"Aria did X. Y is in progress.","frameworkMaturity":"Shield CLEAR.","progress":"• CHG-1 did A","rtb":{"rose":"good","thorn":"bad","bud":"next"}}\nDone!'),
    ("with prose suffix", '{"businessStream":"Aria did X. Y is in progress.","frameworkMaturity":"Shield CLEAR.","progress":"• CHG-1 did A","rtb":{"rose":"good","thorn":"bad","bud":"next"}}\nLet me know if you need more.'),
    ("progress as list", '{"businessStream":"Stream content here.","frameworkMaturity":"Maturity content here.","progress":["CHG-1 did A","CHG-2 did B","CHG-3 did C"],"rtb":{"rose":"good","thorn":"bad","bud":"next"}}'),
    ("short businessStream (should fail)", '{"businessStream":"ok","frameworkMaturity":"Shield CLEAR.","progress":"• CHG-1 did A","rtb":{"rose":"good","thorn":"bad","bud":"next"}}'),
    ("missing rtb (should fail)", '{"businessStream":"Aria did X. Y is in progress.","frameworkMaturity":"Shield CLEAR.","progress":"• CHG-1 did A"}'),
    ("empty progress (should fail)", '{"businessStream":"Aria did X. Y is in progress.","frameworkMaturity":"Shield CLEAR.","progress":"","rtb":{"rose":"good","thorn":"bad","bud":"next"}}'),
    ("trailing comma (real-world LLM)", '{"businessStream":"Aria did X. Y is in progress.","frameworkMaturity":"Shield CLEAR.","progress":"• CHG-1 did A","rtb":{"rose":"good","thorn":"bad","bud":"next",}}'),
    ("nested JSON in string", '{"businessStream":"Aria did X. Y is in progress.","frameworkMaturity":"Shield CLEAR.","progress":"• CHG-1 did A","rtb":{"rose":"good","thorn":"bad","bud":"next"}}'),
    ("unclosed brace (should fail)", '{"businessStream":"Aria did X. Y is in progress.","frameworkMaturity":"Shield CLEAR.","progress":"• CHG-1 did A","rtb":{"rose":"good","thorn":"bad","bud":"next"'),
    ("no JSON at all", 'I cannot answer this question.'),
    ("real-world LLM with json code block and intro", 'Sure! Here is the JSON you asked for:\n\n```json\n{\n  "businessStream": "Aria sent standup. Angie reviewed proposal. LinkedIn draft pending.",\n  "frameworkMaturity": "Shield CLEAR. Lex CLEAR. Sage CONDITIONAL on EOD blog.",\n  "progress": "• CHG-0927 completed\\n• CHG-0928 in progress",\n  "rtb": {\n    "rose": "CHG-0927 closed cleanly",\n    "thorn": "R01 still failing",\n    "bud": "Standup 86 ready to ship"\n  }\n}\n```\n\nLet me know if you need revisions.'),
]

for name, text in test_cases:
    d, msg = validate(text)
    if d is not None:
        print(f"✓ {name}: {msg} | progress={d['progress'][:60]!r}")
    else:
        print(f"✗ {name}: {msg}")
PYEOF
